import requests

def test_get_messages_unauthorized_returns_401():
    base_url = "http://localhost:8000"
    # Use a placeholder conversation_id since no valid JWT is given; can be any UUID format string
    conversation_id = "00000000-0000-0000-0000-000000000000"
    url = f"{base_url}/api/v1/messages/{conversation_id}?page=1"

    headers_missing_auth = {}
    headers_invalid_auth = {"Authorization": "Bearer invalid.jwt.token"}

    def auth_required_in_body(body):
        # Recursively check if any string value in the JSON contains 'authentication required' ignoring case
        if isinstance(body, dict):
            return any(auth_required_in_body(v) for v in body.values())
        elif isinstance(body, list):
            return any(auth_required_in_body(item) for item in body)
        elif isinstance(body, str):
            return 'authentication required' in body.lower()
        return False

    # Test without Authorization header
    try:
        response_no_auth = requests.get(url, headers=headers_missing_auth, timeout=30)
        assert response_no_auth.status_code == 401, f"Expected 401 but got {response_no_auth.status_code}"
        # Check response content for exact authentication required message
        if response_no_auth.headers.get("Content-Type", "").startswith("application/json"):
            body = response_no_auth.json()
            assert auth_required_in_body(body), "Response body does not indicate authentication required"
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    # Test with invalid Authorization header
    try:
        response_invalid_auth = requests.get(url, headers=headers_invalid_auth, timeout=30)
        assert response_invalid_auth.status_code == 401, f"Expected 401 but got {response_invalid_auth.status_code}"
        if response_invalid_auth.headers.get("Content-Type", "").startswith("application/json"):
            body = response_invalid_auth.json()
            assert auth_required_in_body(body), "Response body does not indicate authentication required"
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"


