def test_delete_memories_endpoint_deletes_owned_memory_fact():
    # Step 1: Create a new memory fact by sending a POST /api/v1/message to generate a memory
    # Since APIs for creating memory fact directly are not explicitly given, use GET /memories after generating a message
    # Instead use POST /api/v1/message to send message to create memory indirectly

    message_payload = {
        "content": "Test memory fact for deletion: " + str(uuid.uuid4())
    }

    create_message_resp = requests.post(
        f"{BASE_URL}/api/v1/message",
        headers=HEADERS,
        json=message_payload,
        timeout=30,
    )
    assert create_message_resp.status_code == 200, f"Failed to send message: {create_message_resp.text}"

    # Retrieve memories list to find the new memory_id created
    memories_resp = requests.get(
        f"{BASE_URL}/api/v1/memories",
        headers=HEADERS,
        timeout=30,
    )
    assert memories_resp.status_code == 200, f"Failed to get memories: {memories_resp.text}"
    memories_data = memories_resp.json()
    assert isinstance(memories_data, list) or "memories" in memories_data or isinstance(memories_data, dict), "Unexpected memories response format"

    # Determine memory facts list inside response
    # Based on typical naming memory facts might be in field "memories" or at top level
    # Defensive with keys:
    memory_facts = []
    if isinstance(memories_data, dict):
        # check if 'memories' exists and is a list or fallback keys
        if "memories" in memories_data and isinstance(memories_data["memories"], list):
            memory_facts = memories_data["memories"]
        else:
            # fallback: assume dict values
            memory_facts = [memories_data]
    elif isinstance(memories_data, list):
        memory_facts = memories_data

    assert len(memory_facts) > 0, "No memory facts found for the user"

    # Pick the most recently created memory fact for deletion
    # We try to find the memory fact containing the message content substring
    new_memory_fact = None
    for mem in reversed(memory_facts):
        # Attempt to match content to our sent message by looking for our unique uuid string part
        # Memory fact object is unknown but should contain at least an id and some content/text
        content_fields = []
        if isinstance(mem, dict):
            content_fields = [v for v in mem.values() if isinstance(v, str)]
        for v in content_fields:
            if isinstance(v, str) and message_payload["content"].split()[-1] in v:
                new_memory_fact = mem
                break
        if new_memory_fact:
            break

    assert new_memory_fact is not None, "Could not find the newly created memory fact in memories list"
    memory_id = None
    if "id" in new_memory_fact:
        memory_id = new_memory_fact["id"]
    else:
        # fallback for keys that might have uuid or memory_id
        for k in new_memory_fact:
            if k.lower().endswith("id"):
                memory_id = new_memory_fact[k]
                break
    assert memory_id is not None, "Memory fact does not contain an id field"

    try:
        # Step 2: Send DELETE request to /api/v1/memories/{memory_id}
        delete_resp = requests.delete(
            f"{BASE_URL}/api/v1/memories/{memory_id}",
            headers=HEADERS,
            timeout=30,
        )
        # Step 3: Assert response status code 204 No Content
        assert delete_resp.status_code == 204, f"Expected 204 No Content, got {delete_resp.status_code}, response: {delete_resp.text}"

        # Step 4: Verify the memory fact is removed by fetching memories again and confirming memory_id not present
        memories_after_delete = requests.get(
            f"{BASE_URL}/api/v1/memories",
            headers=HEADERS,
            timeout=30,
        )
        assert memories_after_delete.status_code == 200, f"Failed to get memories after deletion: {memories_after_delete.text}"
        memories_after_data = memories_after_delete.json()

        if isinstance(memories_after_data, dict) and "memories" in memories_after_data:
            memories_list = memories_after_data["memories"]
        elif isinstance(memories_after_data, list):
            memories_list = memories_after_data
        else:
            memories_list = []

        memory_ids_after = set()
        for mem in memories_list:
            if isinstance(mem, dict):
                if "id" in mem:
                    memory_ids_after.add(mem["id"])
                else:
                    for k in mem:
                        if k.lower().endswith("id") and isinstance(mem[k], str):
                            memory_ids_after.add(mem[k])

        assert memory_id not in memory_ids_after, "Memory fact was not removed after DELETE request"
    finally:
        # Cleanup: attempt to delete the memory fact again in case deletion failed
        requests.delete(
            f"{BASE_URL}/api/v1/memories/{memory_id}",
            headers=HEADERS,
            timeout=30,
        )

